from sortedcontainers import SortedDict

class ProductInventory:
    def __init__(self):
        self.inventory = SortedDict()  # Use SortedDict for efficient O(log n) operations

    def is_valid_sku(self, sku):
        return isinstance(sku, str) and sku.isalnum()

    def add_product(self, sku, details):
        if not self.is_valid_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku in self.inventory:
            raise ValueError("Duplicate SKU entry")
        self.inventory[sku] = details

    def update_product(self, sku, details):
        if not self.is_valid_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku not in self.inventory:
            raise ValueError("Nonexistent inventory entry")
        self.inventory[sku] = details

    def delete_product(self, sku):
        if not self.is_valid_sku(sku):
            raise ValueError("Invalid SKU format")
        if sku in self.inventory:
            del self.inventory[sku]
        else:
            raise ValueError("Nonexistent inventory entry")

    def search_product(self, sku):
        if not self.is_valid_sku(sku):
            return None
        return self.inventory.get(sku, None)

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SEATS 100

typedef struct {
    int front, rear, size;
    int seats[MAX_SEATS];
} Queue;

Queue* createQueue() {
    Queue* q = (Queue*)malloc(sizeof(Queue));
    q->front = q->rear = -1;
    q->size = 0;
    return q;
}

bool isFull(Queue* q) {
    return q->size == MAX_SEATS;
}

bool isEmpty(Queue* q) {
    return q->size == 0;
}

bool enqueue(Queue* q, int seat) {
    if (isFull(q))
        return false;
    if (isEmpty(q))
        q->front = 0;
    q->rear = (q->rear + 1) % MAX_SEATS;
    q->seats[q->rear] = seat;
    q->size++;
    return true;
}

bool dequeue(Queue* q, int* seat) {
    if (isEmpty(q))
        return false;
    *seat = q->seats[q->front];
    q->front = (q->front + 1) % MAX_SEATS;
    q->size--;
    if (isEmpty(q))
        q->front = q->rear = -1;
    return true;
}

void initializeSeats(Queue* q) {
    for (int i = 1; i <= MAX_SEATS; i++) {
        enqueue(q, i);
    }
}

bool bookSeat(Queue* q, int* seat) {
    return dequeue(q, seat);
}

bool cancelSeat(Queue* q, int seat) {
    return enqueue(q, seat);
}

int main() {
    Queue* availableSeats = createQueue();
    initializeSeats(availableSeats);

    int seat;
    if (bookSeat(availableSeats, &seat)) {
        printf("Seat %d has been successfully booked.\n", seat);
    } else {
        printf("All seats are full. Cannot book more tickets.\n");
    }

    if (cancelSeat(availableSeats, seat)) {
        printf("Seat %d has been successfully canceled.\n", seat);
    } else {
        printf("Error in canceling the seat.\n");
    }

    free(availableSeats);
    return 0;
}

