fn shuffle<T>(array: &mut [T]) -> Result<(), &'static str> {
    if array.len() == 0 {
        return Err("Array cannot be empty");
    }

    let mut rng = thread_rng();
    array.shuffle(&mut rng);
    Ok(())
}

fn main() {
    let mut nums = vec![1, 2, 3, 4, 5];
    match shuffle(&mut nums) {
        Ok(()) => println!("Shuffled array: {:?}", nums),
        Err(e) => println!("Error: {}", e),
    }

    let mut strs = vec!["a", "b", "c"];
    match shuffle(&mut strs) {
        Ok(()) => println!("Shuffled array: {:?}", strs),
        Err(e) => println!("Error: {}", e),
    }

