#include <iostream>
#include <map>
#include <string>

class LogManager {
public:
    void addLog(int timestamp, const std::string& event) {
        logs.insert({timestamp, event});
    }

    std::vector<std::pair<int, std::string>> queryLogs(int start, int end) {
        auto startIt = logs.lower_bound(start);
        auto endIt = logs.upper_bound(end);

        std::vector<std::pair<int, std::string>> results;
        for (auto it = startIt; it != endIt; ++it) {
            results.push_back(*it);
        }
        return results;
    }

    void updateLogEntry(int oldTimestamp, int newTimestamp, const std::string& newEvent) {
        auto range = logs.equal_range(oldTimestamp);
        for (auto it = range.first; it != range.second; ++it) {
            if (it->second == newEvent) {
                logs.erase(it);
                break;
            }
        }
        addLog(newTimestamp, newEvent);
    }

private:
    std::multimap<int, std::string> logs;
};

int main() {
    LogManager logManager;
    logManager.addLog(1, "Start");
    logManager.addLog(3, "Process");
    logManager.addLog(2, "Load");

    auto logs = logManager.queryLogs(1, 2);
    for (const auto& log : logs)
        std::cout << "Timestamp: " << log.first << ", Event: " << log.second << "\n";

    logManager.updateLogEntry(2, 4, "Updated");
    logs = logManager.queryLogs(1, 4);
    for (const auto& log : logs)
        std::cout << "Timestamp: " << log.first << ", Event: " << log.second << "\n";

    return 0;
}

import java.util.*;

class HierarchicalOrganization {
    private int[][] parent;
    private int[] depth;
    private int LOG;
    private List<List<Integer>> tree;

    public HierarchicalOrganization(int n) {
        LOG = (int) Math.ceil(Math.log(n) / Math.log(2));
        parent = new int[n][LOG];
        depth = new int[n];
        tree = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            tree.add(new ArrayList<>());
        }
    }

    public void addRelation(int superior, int subordinate) {
        tree.get(superior).add(subordinate);
    }

    public void prepareLCA(int root) {
        dfs(root, root);
    }

    private void dfs(int node, int par) {
        parent[node][0] = par;
        for (int i = 1; i < LOG; i++) {
            parent[node][i] = parent[parent[node][i - 1]][i - 1];
        }
        for (int neighbor : tree.get(node)) {
            if (neighbor != par) {
                depth[neighbor] = depth[node] + 1;
                dfs(neighbor, node);
            }
        }
    }

    public void updateHierarchy(int oldSuperior, int newSuperior, int subordinate) {
        int index = tree.get(oldSuperior).indexOf(subordinate);
        if (index != -1) {
            tree.get(oldSuperior).remove(index);
            addRelation(newSuperior, subordinate);
            reDFS(newSuperior, subordinate);
        }
    }

    private void reDFS(int par, int node) {
        depth[node] = depth[par] + 1;
        parent[node][0] = par;
        for (int i = 1; i < LOG; i++) {
            parent[node][i] = parent[parent[node][i - 1]][i - 1];
        }
        for (int neighbor : tree.get(node)) {
            if (neighbor != par) {
                reDFS(node, neighbor);
            }
        }
    }

    public int lowestCommonAncestor(int u, int v) {
        if (depth[u] < depth[v]) {
            int temp = u;
            u = v;
            v = temp;
        }
        int diff = depth[u] - depth[v];
        for (int i = 0; i < LOG; i++) {
            if ((diff & (1 << i)) != 0) {
                u = parent[u][i];
            }
        }
        if (u == v) return u;
        for (int i = LOG - 1; i >= 0; i--) {
            if (parent[u][i] != parent[v][i]) {
                u = parent[u][i];
                v = parent[v][i];
            }
        }
        return parent[u][0];
    }

    public static void main(String[] args) {
        HierarchicalOrganization org = new HierarchicalOrganization(10);
        org.addRelation(0, 1);
        org.addRelation(0, 2);
        org.addRelation(1, 3);
        org.addRelation(1, 4);
        org.addRelation(2, 5);
        org.addRelation(2, 6);
        org.addRelation(3, 7);
        org.addRelation(4, 8);
        org.addRelation(5, 9);

        org.prepareLCA(0);

        System.out.println("LCA of 7 and 8: " + org.lowestCommonAncestor(7, 8)); // Output: 1
        System.out.println("LCA of 3 and 4: " + org.lowestCommonAncestor(3, 4)); // Output: 1 

        org.updateHierarchy(1, 2, 4);

        System.out.println("LCA of 7 and 8 after update: " + org.lowestCommonAncestor(7, 8)); // Output: 2
    }
}

