import java.util.Hashtable;

public class WarehouseInventory {
    private Hashtable<String, String> inventory;

    public WarehouseInventory() {
        inventory = new Hashtable<>();
    }

    public void addItem(String id, String item) {
        inventory.put(id, item);
    }

    public void removeItem(String id) {
        inventory.remove(id);
    }

    public String findItem(String id) {
        return inventory.get(id);
    }

    public void saveInventoryToFile(String filename) throws IOException {
        try (ObjectOutputStream out = new ObjectOutputStream(new FileOutputStream(filename))) {
            out.writeObject(inventory);
        }
    }

    @SuppressWarnings("unchecked")
    public void loadInventoryFromFile(String filename) throws IOException, ClassNotFoundException {
        try (ObjectInputStream in = new ObjectInputStream(new FileInputStream(filename))) {
            inventory = (Hashtable<String, String>) in.readObject();
        }
    }

    public static void main(String[] args) {
        WarehouseInventory wi = new WarehouseInventory();
        wi.addItem("001", "Laptop");
        wi.addItem("002", "Smartphone");
        System.out.println(wi.findItem("001"));
        wi.removeItem("001");
        try {
            wi.saveInventoryToFile("inventory.dat");
            wi.loadInventoryFromFile("inventory.dat");
            System.out.println(wi.findItem("002"));
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

