    void buildSuffixTree() {
        // Implementation of Ukkonen's algorithm to build the suffix tree
        int n = text_.size();
        root_->end = new int(-1);

        Node* lastNewNode = nullptr;
        Node* activeNode = root_;

        int* activeEdge = new int(-1);
        int* activeLength = new int(0);

        for (int i = 0; i < n; i++) {
            int* leafEnd = new int(i);
            int remainingSuffixCount = 0;
            lastNewNode = nullptr;
            remainingSuffixCount++;

            while (remainingSuffixCount > 0) {
                if (*activeLength == 0) *activeEdge = i;

                char currentChar = text_[*activeEdge];
                if (activeNode->children.find(currentChar) == activeNode->children.end()) {
                    activeNode->children[currentChar] = new Node(i, leafEnd);
                    if (lastNewNode != nullptr) {
                        lastNewNode->suffixLink = activeNode;
                        lastNewNode = nullptr;
                    }
                } else {
                    Node* next = activeNode->children[currentChar];
                    int edgeLength = *(next->end) - next->start + 1;

                    if (*activeLength >= edgeLength) {
                        *activeEdge += edgeLength;
                        *activeLength -= edgeLength;
                        activeNode = next;
                        continue;
                    }

                    if (text_[next->start + *activeLength] == text_[i]) {
                        if (lastNewNode != nullptr && activeNode != root_) {
                            lastNewNode->suffixLink = activeNode;
                            lastNewNode = nullptr;
                        }
                        (*activeLength)++;
                        break;
                    }

                    int splitEnd = next->start + *activeLength - 1;
                    Node* split = new Node(next->start, new int(splitEnd));
                    activeNode->children[currentChar] = split;

                    split->children[text_[i]] = new Node(i, leafEnd);
                    next->start += *activeLength;

                    split->children[text_[next->start]] = next;

                    if (lastNewNode != nullptr) {
                        lastNewNode->suffixLink = split;
                    }
                    lastNewNode = split;
                }

                remainingSuffixCount--;

                if (activeNode == root_ && *activeLength > 0) {
                    (*activeLength)--;
                    *activeEdge = i - remainingSuffixCount + 1;
                } else if (activeNode != root_) {
                    activeNode = activeNode->suffixLink;
                }
            }
        }

        delete activeEdge;
        delete activeLength;
    }

    void collectLeafIndices(Node* node, std::vector<int>& indices) const {
        if (node->suffixIndex != -1) {
            indices.push_back(node->suffixIndex);
            return;
        }
        for (const auto& pair : node->children) {
            collectLeafIndices(pair.second, indices);
        }
    }

    void destroyTree(Node* node) {
        if (!node) return;
        for (auto& pair : node->children) {
            destroyTree(pair.second);
        }
        delete node->end;
        delete node;
    }

    std::string text_;
    Node* root_;
};

int main() {
    std::string text;
    std::cout << "Enter text: ";
    std::getline(std::cin, text);

    SuffixTree suffixTree(text);

    std::string pattern;
    std::cout << "Enter substring to find: ";
    std::getline(std::cin, pattern);

    std::vector<int> occurrences = suffixTree.findSubstringOccurrences(pattern);

    if (occurrences.empty()) {
        std::cout << "No occurrences found or empty query." << std::endl;
    } else {
        std::cout << "Occurrences at index(es): ";
        for (int index : occurrences) {
            std::cout << index << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
