    heap->data = (int*)malloc(sizeof(int) * capacity);
    heap->count = 0;
    heap->capacity = capacity;
    return heap;
}

void insert_min_heap(MinHeap* heap, int value) {
    if (heap->count < heap->capacity) {
        // Add new value to the end of the array
        heap->data[heap->count++] = value;
        for (int i = heap->count - 1; i > 0 && heap->data[i] < heap->data[(i-1)/2];) {
            // Sift up
            int tmp = heap->data[i];
            heap->data[i] = heap->data[(i-1)/2];
            heap->data[(i-1)/2] = tmp;
            i = (i-1)/2;
        }
    }
}

void insert_max_heap(MaxHeap* heap, int value) {
