function calculateLCS(word1, word2) {
    // This function assumes the word1 is the smaller one to leverage O(n log n) sorting
    const indices = [];
    const charMap = new Map(); 

    // Map characters of word1 to their indices
    for (let i = 0; i < word1.length; i++) {
        if (!charMap.has(word1[i])) {
            charMap.set(word1[i], []);
        }
        charMap.get(word1[i]).push(i);
    }

    // Gather the indices of word1's characters present in word2
    for (let i = 0; i < word2.length; i++) {
        if (charMap.has(word2[i])) {
            indices.push(...charMap.get(word2[i]));
        }
    }

    // Apply patience sorting to find the increasing sequence of indices
    return patienceSort(indices).map(index => word1[index]).join('');
}

function patienceSort(seq) {
    const piles = [];

    seq.forEach((val) => {
        let left = 0, right = piles.length;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (piles[mid][piles[mid].length - 1] < val) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        if (left === piles.length) piles.push([]);
        piles[left].push(val);
    });

    // reconstruct the longest increasing subsequence
    const result = [];
    for (let i = piles.length - 1; i >= 0; --i) {
        result.push(piles[i].pop());
    }
    result.reverse();
    return result;
}

