class BTreeNode {
    constructor(t, leaf = true) {
        this.t = t; 
        this.leaf = leaf; 
        this.keys = [];
        this.children = [];
    }

    insertNonFull(key) {
        let i = this.keys.length - 1;

        if (this.leaf) {
            while (i >= 0 && key.title < this.keys[i].title) {
                i--;
            }
            this.keys.splice(i + 1, 0, key);
        } else {
            while (i >= 0 && key.title < this.keys[i].title) {
                i--;
            }

            if (this.children[i + 1].keys.length === 2 * this.t - 1) {
                this.splitChild(i + 1, this.children[i + 1]);

                if (key.title > this.keys[i + 1].title) {
                    i++;
                }
            }
            this.children[i + 1].insertNonFull(key);
        }
    }

    splitChild(i, y) {
        let z = new BTreeNode(y.t, y.leaf);
        z.keys = y.keys.splice(this.t);
        if (!y.leaf) {
            z.children = y.children.splice(this.t);
        }
        this.children.splice(i + 1, 0, z);
        this.keys.splice(i, 0, y.keys.splice(this.t - 1, 1)[0]);
    }

    traverse() {
        let result = [];
        for (let i = 0; i < this.keys.length; i++) {
            if (!this.leaf) {
                result = result.concat(this.children[i].traverse());
            }
            result.push(this.keys[i]);
        }

        if (!this.leaf) {
            result = result.concat(this.children[this.keys.length].traverse());
        }

        return result;
    }

    search(keyTitle) {
        let i = 0;
        while (i < this.keys.length && keyTitle > this.keys[i].title) {
            i++;
        }

        if (i < this.keys.length && this.keys[i].title === keyTitle) {
            return this.keys[i];
        }

        if (this.leaf) {
            return null;
        } else {
            return this.children[i].search(keyTitle);
        }
    }
}

class BTree {
    constructor(t) {
        this.root = new BTreeNode(t);
        this.t = t;
    }

    insert(key) {
        let root = this.root;
        if (root.keys.length === 2 * this.t - 1) {
            let s = new BTreeNode(this.t, false);
            this.root = s;
            s.children.push(root);
            s.splitChild(0, root);
            s.insertNonFull(key);
        } else {
            root.insertNonFull(key);
        }
    }

    search(keyTitle) {
        return this.root.search(keyTitle);
    }

    traverse() {
        return this.root.traverse();
    }
}

