public class ShellSortSalaries {

    public static void main(String[] args) {
        String csvFile = "salaries.csv";
        List<Integer> salaries = readSalariesFromCSV(csvFile);
        if (salaries != null) {
            shellSort(salaries);
            System.out.println("Sorted Salaries: " + salaries);
        }
    }

    private static List<Integer> readSalariesFromCSV(String csvFile) {
        List<Integer> salaries = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(csvFile))) {
            String line;
            while ((line = br.readLine()) != null) {
                try {
                    int salary = Integer.parseInt(line.trim());
                    if (salary > 0) {
                        salaries.add(salary);
                    } else {
                        System.err.println("Invalid salary found (not positive): " + salary);
                    }
                } catch (NumberFormatException e) {
                    System.err.println("Invalid number format: " + line);
                }
            }
        } catch (IOException e) {
            System.err.println("Error reading the CSV file: " + e.getMessage());
        }
        return salaries.isEmpty() ? null : salaries;
    }

    private static void shellSort(List<Integer> salaries) {
        int n = salaries.size();
        for (int gap = n / 2; gap > 0; gap /= 2) {
            for (int i = gap; i < n; i++) {
                int temp = salaries.get(i);
                int j;
                for (j = i; j >= gap && salaries.get(j - gap) > temp; j -= gap) {
                    salaries.set(j, salaries.get(j - gap));
                }
                salaries.set(j, temp);
            }
        }
    }
}

class Tab {
  constructor(url) {
    this.url = url;
    this.prev = null;
    this.next = null;
  }
}

class TabHistoryManager {
  constructor() {
    this.currentTab = null;
  }

  openTab(url) {
    const newTab = new Tab(url);
    if (this.currentTab) {
      newTab.prev = this.currentTab;
      this.currentTab.next = null;
    }
    this.currentTab = newTab;
  }

  forward() {
    if (!this.currentTab || !this.currentTab.next) {
      throw new Error('No forward history available');
    }
    this.currentTab = this.currentTab.next;
  }

  back() {
    if (!this.currentTab || !this.currentTab.prev) {
      throw new Error('No backward history available');
    }
    this.currentTab = this.currentTab.prev;
  }

  closeCurrentTab() {
    if (!this.currentTab) {
      throw new Error('No tab to close');
    }
    const prevTab = this.currentTab.prev;
    const nextTab = this.currentTab.next;

    if (prevTab) {
      prevTab.next = nextTab;
    }
    if (nextTab) {
      nextTab.prev = prevTab;
    }

    if (nextTab) {
      this.currentTab = nextTab;
    } else if (prevTab) {
      this.currentTab = prevTab;
    } else {
      this.currentTab = null;
    }
  }

  getCurrentTab() {
    if (!this.currentTab) {
      throw new Error('No current tab');
    }
    return this.currentTab.url;
  }
}

