struct Student {
    std::string name;
    double gpa;
};

bool parseLine(const std::string &line, Student &student) {
    std::istringstream iss(line);
    std::string namePart;
    double gpaPart;
    if (iss >> namePart >> gpaPart) {
        student.name = namePart;
        student.gpa = gpaPart;
        return true;
    }
    return false;
}

void selectionSort(std::vector<Student> &students) {
    int n = students.size();
    for (int i = 0; i < n - 1; ++i) {
        int maxIdx = i;
        for (int j = i + 1; j < n; ++j) {
            if (students[j].gpa > students[maxIdx].gpa) {
                maxIdx = j;
            }
        }
        if (maxIdx != i) {
            std::swap(students[i], students[maxIdx]);
        }
    }
}

int main() {
    std::ifstream inputFile("students.txt");
    std::vector<Student> students;
    std::string line;
    while (std::getline(inputFile, line)) {
        Student student;
        if (parseLine(line, student)) {
            students.push_back(student);
            if (students.size() >= 10000) {
                break;
            }
        }
    }
    inputFile.close();

    selectionSort(students);

    for (const auto &student : students) {
        std::cout << student.name << " " << student.gpa << std::endl;
    }

    return 0;
}

