class SkipListNode {
public:
    int key;
    float value;
    SkipListNode** forward;
    SkipListNode(int key, float value, int level) : key(key), value(value) {
        forward = new SkipListNode*[level + 1];
        memset(forward, 0, sizeof(SkipListNode*) * (level + 1));
    }
    ~SkipListNode() {
        delete[] forward;
    }
};

class SkipList {
private:
    int maxLevel;
    float p;
    int level;
    SkipListNode* header;

    int randomLevel() {
        int lvl = 0;
        while ((float)std::rand() / RAND_MAX < p && lvl < maxLevel) {
            lvl++;
        }
        return lvl;
    }

public:
    SkipList(int maxLevel, float p) : maxLevel(maxLevel), p(p) {
        level = 0;
        header = new SkipListNode(-1, 0.0, maxLevel);
    }

    void insert(int key, float value) {
        SkipListNode* current = header;
        SkipListNode* update[maxLevel + 1];
        memset(update, 0, sizeof(SkipListNode*) * (maxLevel + 1));

        for (int i = level; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->key < key) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (current == nullptr || current->key != key) {
            int rlevel = randomLevel();
            if (rlevel > level) {
                for (int i = level + 1; i < rlevel + 1; i++) {
                    update[i] = header;
                }
                level = rlevel;
            }
            SkipListNode* newNode = new SkipListNode(key, value, rlevel);
            for (int i = 0; i <= rlevel; i++) {
                newNode->forward[i] = update[i]->forward[i];
                update[i]->forward[i] = newNode;
            }
        }
    }

    void remove(int key) {
        SkipListNode* current = header;
        SkipListNode* update[maxLevel + 1];
        memset(update, 0, sizeof(SkipListNode*) * (maxLevel + 1));

        for (int i = level; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->key < key) {
                current = current->forward[i];
            }
            update[i] = current;
        }

        current = current->forward[0];

        if (current != nullptr && current->key == key) {
            for (int i = 0; i <= level; i++) {
                if (update[i]->forward[i] != current) break;
                update[i]->forward[i] = current->forward[i];
            }
            delete current;
            while (level > 0 && header->forward[level] == nullptr) {
                level--;
            }
        }
    }

    float search(int key) {
        SkipListNode* current = header;
        for (int i = level; i >= 0; i--) {
            while (current->forward[i] != nullptr && current->forward[i]->key < key) {
                current = current->forward[i];
            }
        }
        current = current->forward[0];
        if (current != nullptr && current->key == key) {
            return current->value;
        }
        return -1;
    }

    void display() const {
        for (int i = 0; i <= level; i++) {
            SkipListNode* node = header->forward[i];
            while (node != nullptr) {
                std::cout << "(" << node->key << ": " << node->value << ") ";
                node = node->forward[i];
            }
            std::cout << "\n";
        }
    }
};

