use std::cmp::Ordering;

struct Task {
    id: u32,
    urgency: u8,
    resource_availability: u8,
}

impl Task {
    fn new(id: u32, urgency: u8, resource_availability: u8) -> Self {
        Self { id, urgency, resource_availability }
    }

    fn dynamic_priority(&self) -> u32 {
        (self.urgency as u32) * (self.resource_availability as u32)
    }
}

struct PrioritizedTask {
    priority: u32,
    task: Task,
}

impl PartialEq for PrioritizedTask {
    fn eq(&self, other: &Self) -> bool {
        self.priority == other.priority
    }
}

impl Eq for PrioritizedTask {}

impl PartialOrd for PrioritizedTask {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for PrioritizedTask {
    fn cmp(&self, other: &Self) -> Ordering {
        other.priority.cmp(&self.priority) // Reverse to make the largest priority first
    }
}

struct TaskScheduler {
    tasks: BinaryHeap<PrioritizedTask>,
}

impl TaskScheduler {
    fn new() -> Self {
        Self {
            tasks: BinaryHeap::new(),
        }
    }

    fn insert(&mut self, task: Task) {
        self.tasks.push(PrioritizedTask {
            priority: task.dynamic_priority(),
            task,
        });
    }

    fn update_task(&mut self, task_id: u32, new_urgency: u8, new_resource_availability: u8) {
        let mut temp_heap = BinaryHeap::new();
        while let Some(prioritized_task) = self.tasks.pop() {
            if prioritized_task.task.id == task_id {
                let updated_task = Task::new(task_id, new_urgency, new_resource_availability);
                temp_heap.push(PrioritizedTask {
                    priority: updated_task.dynamic_priority(),
                    task: updated_task,
                });
            } else {
                temp_heap.push(prioritized_task);
            }
        }
        self.tasks = temp_heap;
    }

    fn fetch_highest_priority_task(&mut self) -> Option<Task> {
        self.tasks.pop().map(|prioritized_task| prioritized_task.task)
    }
}

fn main() {
    let mut scheduler = TaskScheduler::new();
    scheduler.insert(Task::new(1, 5, 3));
