        this.left = null;
        this.right = null;
    }
}

class AVLTree {
    constructor() {
        this.root = null;
    }

    getHeight(node) {
        if (!node) return 0;
        return node.height;
    }

    getBalance(node) {
        if (!node) return 0;
        return this.getHeight(node.left) - this.getHeight(node.right);
    }

    rightRotate(y) {
        const x = y.left;
        const T2 = x.right;

        x.right = y;
        y.left = T2;

        y.height = Math.max(this.getHeight(y.left), this.getHeight(y.right)) + 1;
        x.height = Math.max(this.getHeight(x.left), this.getHeight(x.right)) + 1;

        return x;
    }

    leftRotate(x) {
        const y = x.right;
        const T2 = y.left;

        y.left = x;
        x.right = T2;

        x.height = Math.max(this.getHeight(x.left), this.getHeight(x.right)) + 1;
        y.height = Math.max(this.getHeight(y.left), this.getHeight(y.right)) + 1;

        return y;
    }

    insert(node, key, score) {
        if (!node) return new Node(key, score);

        if (score < node.score || (score === node.score && key < node.key)) {
            node.left = this.insert(node.left, key, score);
        } else {
            node.right = this.insert(node.right, key, score);
        }

        node.height = 1 + Math.max(this.getHeight(node.left), this.getHeight(node.right));

        const balance = this.getBalance(node);

        if (balance > 1 && score < node.left.score) {
            return this.rightRotate(node);
        }

        if (balance < -1 && score > node.right.score) {
            return this.leftRotate(node);
        }

        if (balance > 1 && score > node.left.score) {
            node.left = this.leftRotate(node.left);
            return this.rightRotate(node);
        }

        if (balance < -1 && score < node.right.score) {
            node.right = this.rightRotate(node.right);
            return this.leftRotate(node);
        }

        return node;
    }

    minValueNode(node) {
        let current = node;
        while (current.left) current = current.left;
        return current;
    }

    deleteNode(root, key, score) {
        if (!root) return root;

        if (score < root.score || (score == root.score && key < root.key)) {
            root.left = this.deleteNode(root.left, key, score);
        } else if (score > root.score || (score == root.score && key > root.key)) {
            root.right = this.deleteNode(root.right, key, score);
        } else {
            if (!root.left || !root.right) {
                root = root.left ? root.left : root.right;
            } else {
                let temp = this.minValueNode(root.right);
                root.key = temp.key;
                root.score = temp.score;
                root.right = this.deleteNode(root.right, temp.key, temp.score);
            }
        }

        if (!root) return root;

        root.height = Math.max(this.getHeight(root.left), this.getHeight(root.right)) + 1;

        const balance = this.getBalance(root);

        if (balance > 1 && this.getBalance(root.left) >= 0) {
            return this.rightRotate(root);
        }

        if (balance > 1 && this.getBalance(root.left) < 0) {
            root.left = this.leftRotate(root.left);
            return this.rightRotate(root);
        }

        if (balance < -1 && this.getBalance(root.right) <= 0) {
            return this.leftRotate(root);
        }

        if (balance < -1 && this.getBalance(root.right) > 0) {
            root.right = this.rightRotate(root.right);
            return this.leftRotate(root);
        }

        return root;
    }

    addUser(key, score) {
        this.root = this.insert(this.root, key, score);
    }

    updateUser(key, newScore) {
        this.root = this.deleteNode(this.root, key, this.getUserScore(key));
        this.addUser(key, newScore);
    }

    getUserScore(node = this.root, key) {
        if (!node) return null;
        if (key === node.key) return node.score;
        if (key < node.key) return this.getUserScore(node.left, key);
        return this.getUserScore(node.right, key);
    }

    getRank(node = this.root, key, score, rank = 1) {
        if (!node) return rank;

        if (score < node.score || (score === node.score && key < node.key)) {
            return this.getRank(node.left, key, score, rank);
        } else if (key !== node.key || score !== node.score) {
            let leftSubtreeSize = this.getSize(node.left) + 1;
            let rightRank = this.getRank(node.right, key, score, rank + leftSubtreeSize);
            return rightRank;
        }

        return rank + this.getSize(node.left);
    }

    getSize(node) {
        if (!node) return 0;
        return 1 + this.getSize(node.left) + this.getSize(node.right);
    }
}

export class Leaderboard {
    constructor() {
        this.tree = new AVLTree();
    }

    addUser(username, score) {
        this.tree.addUser(username, score);
    }

    updateUser(username, newScore) {
        this.tree.updateUser(username, newScore);
    }

    getUserRank(username) {
        let score = this.tree.getUserScore(this.tree.root, username);
        if (score === null) return null;
        return this.tree.getRank(this.tree.root, username, score);
    }
}

