// OrderBook using self-balancing tree map to maintain sorted order prices
class OrderBook {
    std::map<double, Order> book;

public:
    bool validateOrderInput(double price, int quantity, const std::string& type) {
        return (price > 0.0 && quantity > 0 && (type == "buy" || type == "sell"));
    }

    void insertOrder(double price, int quantity, const std::string& type) {
        if (!validateOrderInput(price, quantity, type)) {
            std::cerr << "Invalid order input.\n";
            return;
        }
        auto it = book.find(price);
        if (it != book.end() && it->second.type == type) {
            it->second.quantity += quantity; // Handle duplicates as aggregated orders
        } else {
            book[price] = Order{quantity, type};
        }
    }

    void queryPriceLevel(double price) {
        auto it = book.find(price);
        if (it != book.end()) {
            std::cout << "Price: " << price << ", Quantity: " << it->second.quantity 
                      << ", Type: " << it->second.type << '\n';
        } else {
            std::cout << "No orders at this price level.\n";
        }
    }

    void displayAllOrders() {
        for (const auto& [price, order] : book) {
            std::cout << "Price: " << price << ", Quantity: " << order.quantity 
                      << ", Type: " << order.type << '\n';
        }
    }
};

