#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie { root: TrieNode::default() }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for ch in word.chars() {
            if !node.children.contains_key(&ch) {
                node.children.insert(ch, TrieNode::default());
            }
            node = node.children.get_mut(&ch).unwrap();
        }
        node.is_end_of_word = true;
    }

    fn search(&self, prefix: &str) -> Vec<String> {
        let mut node = &self.root;
        for ch in prefix.chars() {
            if let Some(next_node) = node.children.get(&ch) {
                node = next_node;
            } else {
                return Vec::new();
            }
        }
        let mut words = Vec::new();
        self.collect_words(prefix.to_string(), node, &mut words);
        words
    }

    fn collect_words(&self, prefix: String, node: &TrieNode, words: &mut Vec<String>) {
        if node.is_end_of_word {
            words.push(prefix.clone());
        }
        for (ch, next_node) in &node.children {
            self.collect_words(format!("{}{}", prefix, ch), next_node, words);
        }
    }
}

fn load_words_from_file(trie: &mut Trie, file_path: &str) -> io::Result<()> {
    if let Ok(lines) = read_lines(file_path) {
        for line in lines {
            if let Ok(word) = line {
                let trimmed = word.trim();
                if !trimmed.is_empty() && trimmed.is_char_boundary(0) {
                    trie.insert(trimmed);
                }
            }
        }
    }
    Ok(())
}

fn read_lines<P>(filename: P) -> io::Result<io::Lines<io::BufReader<File>>>
where
    P: AsRef<Path>,
{
    let file = File::open(filename)?;
    Ok(io::BufReader::new(file).lines())
}

