char *LCSubstr(char *X, char *Y) {
    int m = strlen(X);
    int n = strlen(Y);
    int **L = (int **)malloc((m + 1) * sizeof(int *));
    for (int i = 0; i <= m; i++)
        L[i] = (int *)calloc(n + 1, sizeof(int));

    int length = 0;
    int row, col;

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (X[i - 1] == Y[j - 1]) {
                L[i][j] = L[i - 1][j - 1] + 1;
                if (L[i][j] > length) {
                    length = L[i][j];
                    row = i;
                    col = j;
                }
            }
        }
    }

    char *result = (char *)malloc((length + 1) * sizeof(char));
    result[length] = '\0';

    while (L[row][col] != 0) {
        result[--length] = X[row - 1];
        row--;
        col--;
    }

    for (int i = 0; i <= m; i++)
        free(L[i]);
    free(L);

    return result;
}

