// Define the packet structure
typedef struct Packet {
    int id;
    int priority;
    char data[256];
} Packet;

// Define the Node for a priority queue implemented as a min-heap
typedef struct HeapNode {
    Packet packet;
} HeapNode;

// Define the priority queue
typedef struct PriorityQueue {
    HeapNode* nodes;
    int capacity;
    int size;
} PriorityQueue;

// Function prototypes
PriorityQueue* createPriorityQueue(int capacity);
void insertPacket(PriorityQueue* pq, Packet packet);
Packet extractMin(PriorityQueue* pq);
void heapifyUp(PriorityQueue* pq, int index);
void heapifyDown(PriorityQueue* pq, int index);
int isValidPacket(Packet packet);
void logPacketProcessing(Packet packet);
void freePriorityQueue(PriorityQueue* pq);

// Main function
int main() {
    PriorityQueue* pq = createPriorityQueue(100);

    // Simulate packet arrival and processing
    Packet p1 = {1, 2, "Data1"};
    Packet p2 = {2, 1, "Data2"};
    Packet p3 = {3, 3, "Data3"};

    if(isValidPacket(p1)) insertPacket(pq, p1);
    if(isValidPacket(p2)) insertPacket(pq, p2);
    if(isValidPacket(p3)) insertPacket(pq, p3);

    while(pq->size > 0) {
        Packet processedPacket = extractMin(pq);
        logPacketProcessing(processedPacket);
    }

    freePriorityQueue(pq);
    return 0;
}

// Function implementations

PriorityQueue* createPriorityQueue(int capacity) {
    PriorityQueue* pq = (PriorityQueue*)malloc(sizeof(PriorityQueue));
    pq->nodes = (HeapNode*)malloc(capacity * sizeof(HeapNode));
    pq->capacity = capacity;
    pq->size = 0;
    return pq;
}

void insertPacket(PriorityQueue* pq, Packet packet) {
    if (pq->size == pq->capacity) {
        printf("Priority Queue is full\n");
        return;
    }
    HeapNode node = {packet};
    pq->nodes[pq->size] = node;
    pq->size++;
    heapifyUp(pq, pq->size - 1);
}

Packet extractMin(PriorityQueue* pq) {
    if (pq->size <= 0) {
        printf("Priority Queue is empty\n");
        Packet empty = {-1, -1, ""};
        return empty;
    }
    Packet minPacket = pq->nodes[0].packet;
    pq->nodes[0] = pq->nodes[pq->size - 1];
    pq->size--;
    heapifyDown(pq, 0);
    return minPacket;
}

void heapifyUp(PriorityQueue* pq, int index) {
    while(index > 0) {
        int parentIdx = (index - 1) / 2;
        if (pq->nodes[index].packet.priority < pq->nodes[parentIdx].packet.priority) {
            HeapNode temp = pq->nodes[index];
            pq->nodes[index] = pq->nodes[parentIdx];
            pq->nodes[parentIdx] = temp;
            index = parentIdx;
        } else break;
    }
}

void heapifyDown(PriorityQueue* pq, int index) {
    while(1) {
        int leftIdx = 2 * index + 1;
        int rightIdx = 2 * index + 2;
        int smallest = index;

        if (leftIdx < pq->size && pq->nodes[leftIdx].packet.priority < pq->nodes[smallest].packet.priority) {
            smallest = leftIdx;
        }
        if (rightIdx < pq->size && pq->nodes[rightIdx].packet.priority < pq->nodes[smallest].packet.priority) {
            smallest = rightIdx;
        }
        if (smallest != index) {
            HeapNode temp = pq->nodes[index];
            pq->nodes[index] = pq->nodes[smallest];
            pq->nodes[smallest] = temp;
            index = smallest;
        } else break;
    }
}

int isValidPacket(Packet packet) {
    if (packet.priority < 0 || packet.priority > 10) {
        printf("Invalid priority for packet %d\n", packet.id);
        return 0;
    }
    return 1;
}

void logPacketProcessing(Packet packet) {
    printf("Processing Packet ID: %d with Priority: %d, Data: %s\n", packet.id, packet.priority, packet.data);
}

void freePriorityQueue(PriorityQueue* pq) {
    if (pq) {
        free(pq->nodes);
        free(pq);
    }
