fn print_board(board: &[Vec<u8>]) {
    for row in board {
        for &val in row {
            print!("{} ", if val == 1 { "Q" } else { "." });
        }
        println!();
    }
    println!();
}

fn is_safe(board: &[Vec<u8>], row: usize, col: usize, n: usize) -> bool {
    for i in 0..col {
        if board[row][i] == 1 {
            return false;
        }
    }

    for (i, j) in (0..=row).rev().zip((0..=col).rev()) {
        if board[i][j] == 1 {
            return false;
        }
    }

    for (i, j) in (row..n).zip((0..=col).rev()) {
        if board[i][j] == 1 {
            return false;
        }
    }

    true
}

fn solve(board: &mut Vec<Vec<u8>>, col: usize, n: usize) -> bool {
    if col >= n {
        print_board(&board);
        return true;
    }

    for i in 0..n {
        if is_safe(board, i, col, n) {
            board[i][col] = 1;

            solve(board, col + 1, n);

            board[i][col] = 0;
        }
    }

    false
}

fn solve_n_queens(n: usize) {
    let mut board = vec![vec![0; n]; n];
    solve(&mut board, 0, n);
}

