}

function findShortestPath(graph, start, end) {
    if (!graph[start] || !graph[end]) return "Invalid input: Start or End intersection does not exist";

    const distances = {};
    const previous = {};
    const queue = new Set();

    for (const intersection in graph) {
        distances[intersection] = Infinity;
        previous[intersection] = null;
        queue.add(intersection);
    }
    distances[start] = 0;

    while (queue.size) {
        let current = null;
        let currentDistance = Infinity;
        for (const intersection of queue) {
            if (distances[intersection] < currentDistance) {
                currentDistance = distances[intersection];
                current = intersection;
            }
        }

        if (current === end) {
            const path = [];
            while (previous[current]) {
                path.unshift(current);
                current = previous[current];
            }
            path.unshift(start);
            return path;
        }

        if (currentDistance === Infinity) return "Unreachable destination";

        queue.delete(current);

        for (const neighbor in graph[current]) {
            const alt = distances[current] + graph[current][neighbor];
            if (alt < distances[neighbor]) {
                distances[neighbor] = alt;
                previous[neighbor] = current;
            }
        }
    }

    return "Unreachable destination";
}

