#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <limits>

struct Point {
    double x, y;
    Point(double x, double y) : x(x), y(y) {}
};

double distance(const Point& p1, const Point& p2) {
    return std::sqrt((p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y));
}

Point findNearestShop(Point userLocation, const std::vector<Point>& coffeeShops) {
    // Sort coffee shops by their x-coordinate to apply Divide and Conquer technique.
    std::vector<Point> sortedShops(coffeeShops);
    std::sort(sortedShops.begin(), sortedShops.end(), [](const Point& p1, const Point& p2) {
        return p1.x < p2.x;
    });

    return divideAndConquer(sortedShops, userLocation, 0, sortedShops.size());
}

Point divideAndConquer(const std::vector<Point>& sortedShops, const Point& userLocation, size_t left, size_t right) {
    if (right - left <= 3) {  // Base case: small size, use brute force
        return bruteForceNearest(sortedShops, userLocation, left, right);
    }

    size_t mid = left + (right - left) / 2;

    Point leftNearest = divideAndConquer(sortedShops, userLocation, left, mid);
    Point rightNearest = divideAndConquer(sortedShops, userLocation, mid, right);

    double leftDist = distance(userLocation, leftNearest);
    double rightDist = distance(userLocation, rightNearest);

    Point nearest = (leftDist < rightDist) ? leftNearest : rightNearest;
    double minDist = std::min(leftDist, rightDist);

    // Check points near the line between left and right halves
    std::vector<Point> strip;
    for (size_t i = left; i < right; ++i) {
        if (std::abs(sortedShops[i].x - sortedShops[mid].x) < minDist) {
            strip.push_back(sortedShops[i]);
        }
    }

    std::sort(strip.begin(), strip.end(), [](const Point& p1, const Point& p2) {
        return p1.y < p2.y;
    });

    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < minDist; ++j) {
            double dist = distance(userLocation, strip[j]);
            if (dist < minDist) {
                minDist = dist;
                nearest = strip[j];
            }
        }
    }

    return nearest;
}

Point bruteForceNearest(const std::vector<Point>& coffeeShops, const Point& userLocation, size_t left, size_t right) {
    Point closestShop = coffeeShops[left];
    double minDist = distance(userLocation, closestShop);

    for (size_t i = left + 1; i < right; ++i) {
        double dist = distance(userLocation, coffeeShops[i]);
        if (dist < minDist) {
            minDist = dist;
            closestShop = coffeeShops[i];
        }
    }

    return closestShop;
}

